head.script:
scwin.afterSaveRetrieveYN = "YES";
scwin.g_chkScroll = false;
scwin.g_chkScroll2 = false;

scwin.v_odrNo = "";
scwin.v_cntrSeq = 0;
scwin.v_wrkLobranCd = "";
scwin.v_reqClsCd = "";
scwin.v_transCls = "";
scwin.v_cntrSizCd = "";
scwin.v_cntrTypCd = "";
scwin.v_reqDt = "";
scwin.v_reqHh = "";
scwin.v_reqDoorCd = "";

scwin.nowDt = "";
scwin.lobranCd = "";
scwin.odrNo = "";
scwin.wrkStDt = "";
scwin.wrkEndDt = "";
scwin.cntrNo = "";
scwin.loUpperLobranCd = "";
scwin.PCHS_CLNT_CLS_CD_HIRECAR = "";
scwin.WRK_STP_CD_RETRV = "";
scwin.CNTR_WRK_KND_CD_BOBTAIL = "";
scwin.CNTR_WRK_KND_CD_ONGROUND = "";

scwin.hid_vehclNo = "";
scwin.hid_vehclClntNo = "";
scwin.hid_vehclClntNm = "";
scwin.hid_drvNm = "";
scwin.hid_mpNo = "";
scwin.hid_eqCd = "";
scwin.hid_pdaYn = "";
scwin.hid_chassisEqCd = "";
scwin.hid_chassisKndCd = "";
scwin.hid_chassisNo = "";

scwin.onpageload = async function() {
    scwin.nowDt = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    let params = $c.data.getParameter();
    if (params != null) {
        scwin.lobranCd = params.lobranCd || "";
        scwin.odrNo = params.odrNo || "";
        scwin.wrkStDt = params.wrkStDt || "";
        scwin.wrkEndDt = params.wrkEndDt || "";
        scwin.cntrNo = params.cntrNo || "";
    }
    scwin.loUpperLobranCd = $c.ses.getLoUpperLobranCd();
    scwin.PCHS_CLNT_CLS_CD_HIRECAR = $c.ses.getConstant("PCHS_CLNT_CLS_CD_HIRECAR") || "";
    scwin.WRK_STP_CD_RETRV = $c.ses.getConstant("WRK_STP_CD_RETRV") || "";
    scwin.CNTR_WRK_KND_CD_BOBTAIL = $c.ses.getConstant("CNTR_WRK_KND_CD_BOBTAIL") || "";
    scwin.CNTR_WRK_KND_CD_ONGROUND = $c.ses.getConstant("CNTR_WRK_KND_CD_ONGROUND") || "";

    scwin.f_OnLoad();
};

scwin.onUdcCompleted = async function() {
};

scwin.f_OnLoad = async function() {
    let data = $c.data.getParameter();
    if (data == null) data = {};
    let dataArr = [];
    dataArr[0] = data.p0 || "";
    dataArr[1] = data.p1 || "";
    dataArr[2] = data.p2 || "";
    dataArr[3] = data.p3 || "";
    dataArr[4] = data.p4 || "";
    dataArr[5] = data.p5 || "";
    dataArr[6] = data.p6 || "";
    dataArr[7] = data.p7 || "";
    dataArr[8] = data.p8 || "";
    dataArr[9] = data.p9 || "";

    scwin.v_odrNo = dataArr[0];
    scwin.v_cntrSeq = dataArr[1];
    scwin.v_wrkLobranCd = dataArr[2];
    scwin.v_reqClsCd = dataArr[3];
    scwin.v_transCls = dataArr[4];
    scwin.v_cntrSizCd = dataArr[5];
    scwin.v_cntrTypCd = dataArr[6];
    scwin.v_reqDt = dataArr[7];
    scwin.v_reqHh = dataArr[8];
    scwin.v_reqDoorCd = dataArr[9];

    dma_retrieve2.set("odrNo", dataArr[0]);
    dma_retrieve2.set("cntrSeq", dataArr[1]);
    dma_retrieve2.set("wrkLobranCd", dataArr[2]);
    dma_retrieve2.set("reqClsCd", dataArr[3]);
    dma_retrieve2.set("transCls", dataArr[4]);
    dma_retrieve2.set("cntrSizCd", dataArr[5]);
    dma_retrieve2.set("cntrTypCd", dataArr[6]);
    dma_retrieve2.set("reqDt", dataArr[7]);
    dma_retrieve2.set("reqHh", dataArr[8]);
    dma_retrieve2.set("reqDoorCd", dataArr[9]);

    await $c.sbm.execute(sbm_retrieve2);

    if (scwin.wrkStDt == "") {
        ica_rsltsDptDd.setValue(scwin.nowDt);
        ica_rsltsArvDd.setValue(scwin.nowDt);
    } else {
        ica_rsltsDptDd.setValue(scwin.wrkStDt);
        ica_rsltsArvDd.setValue(scwin.wrkEndDt);
    }

    if (scwin.cntrNo != "") {
        scwin.f_Retrieve();
    } else if (scwin.odrNo != "") {
        scwin.f_Retrieve();
    }
};

scwin.f_Retrieve = async function() {
    scwin.g_chkScroll = false;
    scwin.g_chkScroll2 = false;
    await $c.sbm.execute(sbm_retrieve);
};

scwin.f_Retrieve2 = async function() {
    dma_retrieve2.set("odrNo", scwin.v_odrNo);
    dma_retrieve2.set("cntrSeq", scwin.v_cntrSeq);
    dma_retrieve2.set("wrkLobranCd", scwin.v_wrkLobranCd);
    dma_retrieve2.set("reqClsCd", scwin.v_reqClsCd);
    dma_retrieve2.set("transCls", scwin.v_transCls);
    dma_retrieve2.set("cntrSizCd", scwin.v_cntrSizCd);
    dma_retrieve2.set("cntrTypCd", scwin.v_cntrTypCd);
    dma_retrieve2.set("reqDt", scwin.v_reqDt);
    dma_retrieve2.set("reqHh", scwin.v_reqHh);
    dma_retrieve2.set("reqDoorCd", scwin.v_reqDoorCd);
    await $c.sbm.execute(sbm_retrieve2);
};

scwin.f_Save = async function(retrieveYn) {
    if (ds_results2.getUpdatedIndex().length == 0 && ds_dcScList.getUpdatedIndex().length == 0) {
        await $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    for (let i = 0; i < ds_results2.getRowCount(); i++) {
        if (ds_results2.getCellData(i, "vehclClntNo") == ds_results2.getCellData(i, "bilgClntNo")) {
            await $c.win.alert("오더의 청구거래처와 협력 운송업체가 동일한 경우 저장 할 수 없습니다.");
            return false;
        }
    }

    for (let i = 0; i < ds_results2.getRowCount(); i++) {
        if (ds_results2.getCellData(i, "alloccarCls") == "N") {
            if (ds_results2.getRowStatus(i) == "U") {
                if (ds_results2.getCellData(i, "cntrWrkShapeCd") != "") {
                    if (ds_results2.getCellData(i, "wrkStpCd") == "0002") {
                        if (i + 1 < ds_results2.getRowCount() && ds_results2.getCellData(i + 1, "wrkStpCd") == "0003" && ds_results2.getCellData(i + 1, "vehclNo") != "") {
                            if (ds_results2.getCellData(i, "odrNo") == ds_results2.getCellData(i + 1, "odrNo") && ds_results2.getCellData(i, "cntrSeq") == ds_results2.getCellData(i + 1, "cntrSeq")) {
                                await $c.win.alert("DOOR운송 배차시, BOBTAIL, ON-GROUND를 선택하고 배차할 때는 회수단계는 차량이 없어야 합니다.");
                                ds_results2.setCellData(i + 1, "vehclNo", "");
                                ds_results2.setCellData(i + 1, "vehclShortNo", "");
                                ds_results2.setCellData(i + 1, "vehclClntNo", "");
                                ds_results2.setCellData(i + 1, "vehclClntNm", "");
                                ds_results2.setCellData(i + 1, "drvNm", "");
                                ds_results2.setCellData(i + 1, "mpNo", "");
                                ds_results2.setCellData(i + 1, "eqCd", "");
                                ds_results2.setCellData(i + 1, "chassShortNo", "");
                                ds_results2.setCellData(i + 1, "chassisEqCd", "");
                                ds_results2.setCellData(i + 1, "chassisKndCd", "");
                                ds_results2.setCellData(i + 1, "chassisVehclNo", "");
                                return false;
                            }
                        }
                    } else if (ds_results2.getCellData(i, "wrkStpCd") == "0003") {
                        if (i - 1 >= 0 && ds_results2.getCellData(i - 1, "wrkStpCd") == "0002" && ds_results2.getCellData(i - 1, "vehclNo") != "" && ds_results2.getCellData(i - 1, "alloccarCls") == "N") {
                            if (ds_results2.getCellData(i, "odrNo") == ds_results2.getCellData(i - 1, "odrNo") && ds_results2.getCellData(i, "cntrSeq") == ds_results2.getCellData(i - 1, "cntrSeq")) {
                                await $c.win.alert("DOOR회수 배차시, BOBTAIL, ON-GROUND를 선택하고 운송단계보다 먼저 배차할 수 없습니다.");
                                ds_results2.setCellData(i - 1, "vehclNo", "");
                                ds_results2.setCellData(i - 1, "vehclShortNo", "");
                                ds_results2.setCellData(i, "vehclNo", "");
                                ds_results2.setCellData(i, "vehclShortNo", "");
                                return false;
                            }
                        }
                    } else if (ds_results2.getCellData(i, "wrkStpCd") == "0047") {
                        await $c.win.alert("육송 단계는 BOBTAIL, ON-GROUND로 배차할 수 없습니다");
                        return false;
                    }
                }
            }
        }
    }

    for (let i = 0; i < ds_results2.getRowCount(); i++) {
        if (ds_results2.getCellData(i, "alloccarCls") == "Y") {
            if (ds_results2.getRowStatus(i) == "U") {
                if (ds_results2.getCellData(i, "cooperatorYn") == 1) {
                    if (ds_results2.getCellData(i, "vehclNo") != "") {
                        await $c.win.alert("컨테이너 " + ds_results2.getCellData(i, "cntrNo") + " 는 협력업체에서 이미 배차한 물량은 취소할 수 없습니다. \n협력업체에서 먼저 배차를 취소한 후 취소할 수 있습니다.");
                        return false;
                    }
                }
            } 
        } else {
            if ("B" == ds_results2.getCellData(i, "reqClsCd") || "C" == ds_results2.getCellData(i, "reqClsCd")) {
                if ($c.gus.cfIsNull(ds_results2.getCellData(i, "vehclNo")) && !$c.gus.cfIsNull(ds_results2.getCellData(i, "vehclClntNo"))) {
                    await $c.win.alert("미지정(컨테이너), 지정범위 요청 건은 협력업체 배차 불가 합니다.");
                    return false;
                }
            }
        }
    }

    scwin.afterSaveRetrieveYN = retrieveYn;
    await $c.sbm.execute(sbm_save);
};

scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;
    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList;
    switch (disGubun) {
        case 4:
            udc_clnt.ilCommonPopUp(scwin.callbackCase4,
                pCode, pName, pClose, null, null, null, null,
                scwin.PCHS_CLNT_CLS_CD_HIRECAR, null, null, null, null, null,
                pAllSearch, "협력업체,협력업체코드/명,");
            break;
        case 5:
            udc_clnt.ilCommonPopUp(scwin.callbackCase5,
                pCode, pName, pClose, null, null, null, null,
                null, null, null, null, null, null,
                pAllSearch, null);
            break;
        case 7:
            udc_clnt.ilCommonPopUp(scwin.callbackCase7,
                pCode, pName, pClose, null, null, null, null,
                'C', null, null, null, null, null,
                'F', null);
            break;
        default:
            break;
    }
};

scwin.callbackCase4 = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, em_clntNo, txt_clntNm);
};

scwin.callbackCase5 = async function(rtnList) {
    // TODO: em_alloccarPicId, txt_alloccarPicNm not in body - map to available components
};

scwin.callbackCase7 = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, em_shortChassNo, null);
    scwin.hid_chassisEqCd = rtnList[4];
    scwin.hid_chassisKndCd = rtnList[2];
};

scwin.f_openCommPopUpGrid = async function(disGubun, row, pClose) {
    let rtnList;
    let pCode = "";
    let pName = "";

    switch (disGubun) {
        case 2:
            pCode = ds_results2.getCellData(row, "chassShortNo");
            if ($c.gus.cfIsNull(pCode)) {
                ds_results2.setCellData(row, "chassisEqCd", "");
                ds_results2.setCellData(row, "chassisKndCd", "");
                ds_results2.setCellData(row, "chassisVehclNo", "");
                break;
            }
            udc_clnt.ilCommonPopUp(function(rtnList) {
                scwin.callbackGridChassis(rtnList, row);
            }, pCode, pName, pClose, null, null, null, null, 'C', null, null, null, null, null, 'F', null);
            break;
        default:
            break;
    }
};

scwin.callbackGridChassis = async function(rtnList, row) {
    $c.gus.cfSetGridReturnValue(rtnList, ds_results2, row, "chassShortNo", "");
    ds_results2.setCellData(row, "chassisEqCd", rtnList[4]);
    ds_results2.setCellData(row, "chassisKndCd", rtnList[2]);
    ds_results2.setCellData(row, "chassisVehclNo", rtnList[1]);
    ds_results2.setCellData(row, "chassShortNo", rtnList[14]);
    scwin.f_checkChasisNo(row);

    let vOdrNo = ds_results2.getCellData(row, "odrNo");
    let vCntrSeq = ds_results2.getCellData(row, "cntrSeq");
    let vChassisEqCd = ds_results2.getCellData(row, "chassisEqCd");
    let vChassisKndCd = ds_results2.getCellData(row, "chassisKndCd");
    let vChassShortNo = ds_results2.getCellData(row, "chassShortNo");
    let vChassisVehclNo = ds_results2.getCellData(row, "chassisVehclNo");

    for (let i = 0; i < ds_results2.getRowCount(); i++) {
        if (vOdrNo == ds_results2.getCellData(i, "odrNo") && vCntrSeq == ds_results2.getCellData(i, "cntrSeq")) {
            ds_results2.setCellData(i, "chassisEqCd", vChassisEqCd);
            ds_results2.setCellData(i, "chassisKndCd", vChassisKndCd);
            ds_results2.setCellData(i, "chassShortNo", vChassShortNo);
            ds_results2.setCellData(i, "chassisVehclNo", vChassisVehclNo);
        }
    }

    sbm_retrieveChassis.action = "/tn.op.transwrkindict.cntr.RetrieveCarInspInfoCMD.do?chassShortNo=" + ds_results2.getCellData(row, "chassShortNo");
    await $c.sbm.execute(sbm_retrieveChassis);
};

scwin.f_runExcel = async function(varGrNm) {
    let totCnt = varGrNm.getRowCount();
    let sheetTitle = "컨테이너운송지시";
    if (totCnt != 0) {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            $c.data.downloadGridViewExcel(varGrNm, { fileName: sheetTitle + ".xlsx", sheetName: sheetTitle });
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

scwin.f_filter = async function() {
    ds_results2.filter();
};

scwin.f_deleteRow = async function() {
    let row = ds_results2.getRowPosition();
    ds_results2.undoRow(row);
    if (ds_results2.getCellData(row, "alloccarCls") == "Y") {
        let unCheckedRow = ds_results2.getRowPosition();
        let delCnt = 0;
        for (let i = 0; i < ds_results2.getRowCount(); i++) {
            if ("B" == ds_results2.getCellData(i, "reqClsCd") || "C" == ds_results2.getCellData(i, "reqClsCd")) {
                if ((ds_results2.getOrgCellData(unCheckedRow, "vehclNo") == ds_results2.getCellData(i, "vehclNo"))
                    && (ds_results2.getOrgCellData(unCheckedRow, "wrkStpCd") == ds_results2.getCellData(i, "wrkStpCd"))
                    && delCnt < 1) {
                    if (ds_results2.getCellData(i, "alloccarCls") == "Y") {
                        if (ds_results2.getCellData(i, "cooperatorYn") == 0) {
                            ds_results2.setCellData(i, "vehclNo", "");
                            ds_results2.setCellData(i, "vehclShortNo", "");
                            ds_results2.setCellData(i, "cntrWrkShapeCd", "");
                        } else {
                            ds_results2.setCellData(i, "vehclClntNo", "");
                            ds_results2.setCellData(i, "vehclShortNo", "");
                            ds_results2.setCellData(i, "cntrWrkShapeCd", "");
                        }
                    }
                    delCnt++;
                }
                if ((ds_results2.getOrgCellData(unCheckedRow, "vehclNo") == ds_results2.getCellData(i, "vehclNo"))
                    && (ds_results2.getOrgCellData(unCheckedRow, "wrkStpCd") != ds_results2.getCellData(i, "wrkStpCd"))
                    && delCnt < 2) {
                    if (ds_results2.getCellData(i, "alloccarCls") == "Y") {
                        if (ds_results2.getCellData(i, "cooperatorYn") == 0) {
                            ds_results2.setCellData(i, "vehclNo", "");
                            ds_results2.setCellData(i, "vehclShortNo", "");
                            ds_results2.setCellData(i, "cntrWrkShapeCd", "");
                        } else {
                            ds_results2.setCellData(i, "vehclClntNo", "");
                            ds_results2.setCellData(i, "vehclShortNo", "");
                            ds_results2.setCellData(i, "cntrWrkShapeCd", "");
                        }
                    }
                    delCnt++;
                }
            } else {
                if (ds_results2.getCellData(unCheckedRow, "transWrkIndictNo") == ds_results2.getCellData(i, "transWrkIndictNo")) {
                    if (ds_results2.getCellData(i, "alloccarCls") == "Y") {
                        if (ds_results2.getCellData(i, "cooperatorYn") == 0) {
                            ds_results2.setCellData(i, "vehclNo", "");
                            ds_results2.setCellData(i, "vehclShortNo", "");
                        } else {
                            ds_results2.setCellData(i, "vehclClntNo", "");
                            ds_results2.setCellData(i, "vehclShortNo", "");
                        }
                    }
                }
            }
        }
    }
};

scwin.f_setVehclClntNoToChecked = async function() {
    if (em_clntNo.getValue() == "") {
        await $c.win.alert("협력업체를 선택하여 주십시오");
        em_clntNo.setFocus();
        return false;
    }
    for (let i = 0; i < ds_results2.getRowCount(); i++) {
        if (ds_results2.getCellData(i, "chk") == 1
            && ds_results2.getCellData(i, "vehclNo") == ""
            && (ds_results2.getCellData(i, "reqClsCd") == "A" || ds_results2.getCellData(i, "reqClsCd") == "D")) {

            ds_results2.setCellData(i, "vehclClntNo", em_clntNo.getValue());
            ds_results2.setCellData(i, "vehclClntNm", txt_clntNm.getValue());

            let lv_odrNo = ds_results2.getCellData(i, "odrNo");
            let lv_cntrSeq = ds_results2.getCellData(i, "cntrSeq");
            let lv_vehclClntNo = ds_results2.getCellData(i, "vehclClntNo");

            for (let j = 0; j < ds_results2.getRowCount(); j++) {
                if (ds_results2.getCellData(j, "vehclClntNo") != ""
                    && i != j
                    && lv_odrNo == ds_results2.getCellData(j, "odrNo")
                    && lv_cntrSeq == ds_results2.getCellData(j, "cntrSeq")
                    && lv_vehclClntNo != ds_results2.getCellData(j, "vehclClntNo")) {

                    await $c.win.alert("같은 오더, 컨테이너에 운송단계를 각각 다른  협력업체로 지정하여 동시에 배차할 수 없습니다. \n 운송단계 배차한 후에 회수단계를 배차하여 주시기 바랍니다.");
                    ds_results2.setCellData(i, "vehclClntNo", "");
                    ds_results2.setCellData(i, "vehclClntNm", "");
                    ds_results2.setCellData(i, "chk", 0);
                    return false;
                }
            }
        }
    }
};

scwin.f_setVehclNoAndChassisToChecked = async function() {
    if (em_shortVhclNo.getValue() == "" && em_shortChassNo.getValue() == "") {
        await $c.win.alert("차량이나 샤시를 선택하여 주십시오");
        em_shortVhclNo.setFocus();
        return false;
    }
    let chkCnt = 0;
    for (let i = 0; i < ds_results2.getRowCount(); i++) {
        if (ds_results2.getCellData(i, "chk") == 1) {
            if (ds_results2.getCellData(i, "alloccarCls") == "N") {
                ds_results2.setCellData(i, "vehclShortNo", em_shortVhclNo.getValue());
                ds_results2.setCellData(i, "vehclNo", scwin.hid_vehclNo);
                ds_results2.setCellData(i, "vehclClntNo", scwin.hid_vehclClntNo);
                ds_results2.setCellData(i, "vehclClntNm", scwin.hid_vehclClntNm);
                ds_results2.setCellData(i, "drvNm", scwin.hid_drvNm);
                ds_results2.setCellData(i, "mpNo", scwin.hid_mpNo);
                ds_results2.setCellData(i, "eqCd", scwin.hid_eqCd);
                ds_results2.setCellData(i, "pdaYn", scwin.hid_pdaYn);
                ds_results2.setCellData(i, "chassShortNo", em_shortChassNo.getValue());
                ds_results2.setCellData(i, "chassisEqCd", scwin.hid_chassisEqCd);
                ds_results2.setCellData(i, "chassisKndCd", scwin.hid_chassisKndCd);
                scwin.f_checkChasisNo(i);
                chkCnt++;
            } else {
                ds_results2.setCellData(i, "chk", 0);
            }
        }
    }
    if (chkCnt == 0) {
        await $c.win.alert("check된 물량이 없습니다. 원하는 물량을 체크한 후에 차량배정 버튼을 누르면 체크된 행에 차량과 샤시번호가 setting됩니다");
        return false;
    }
};

scwin.f_retrieveVehclInGrid = async function() {
    let row = ds_results2.getRowPosition();
    let pURL = "/ui/tn/op/transwrkindict/cntr/tn_304_01_05p.xml";
    let obj = {
        paramTitle: "차량정보",
        vehclShortNo: ds_results2.getCellData(row, "vehclShortNo"),
        whereAreYouFrom: "T"
    };
    let rtnList = await $c.win.openPopup(pURL, { width: 930, height: 500, modal: true, data: obj });

    if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A") {
        let unCheckedRow = ds_results2.getRowPosition();

        ds_results2.setCellData(unCheckedRow, "vehclShortNo", rtnList[0]);
        ds_results2.setCellData(unCheckedRow, "vehclNo", rtnList[1]);
        ds_results2.setCellData(unCheckedRow, "vehclClntNo", rtnList[7]);
        ds_results2.setCellData(unCheckedRow, "vehclClntNm", rtnList[8]);
        ds_results2.setCellData(unCheckedRow, "drvNm", rtnList[18]);
        ds_results2.setCellData(unCheckedRow, "mpNo", rtnList[17]);
        ds_results2.setCellData(unCheckedRow, "eqCd", rtnList[4]);
        ds_results2.setCellData(unCheckedRow, "posnClsCd", rtnList[21]);

        if (ds_results2.getCellData(unCheckedRow, "chassisEqCd") == "") {
            if (ds_results2.getCellData(unCheckedRow, "posnClsCd") == "W" || ds_results2.getCellData(unCheckedRow, "posnClsCd") == "G") {
                ds_results2.setCellData(unCheckedRow, "chassShortNo", "");
                ds_results2.setCellData(unCheckedRow, "chassisEqCd", "");
                ds_results2.setCellData(unCheckedRow, "chassisKndCd", "");
                ds_results2.setCellData(unCheckedRow, "chassisVehclNo", "");
            } else {
                ds_results2.setCellData(unCheckedRow, "chassShortNo", rtnList[14]);
                ds_results2.setCellData(unCheckedRow, "chassisEqCd", rtnList[12]);
                ds_results2.setCellData(unCheckedRow, "chassisKndCd", rtnList[16]);
                ds_results2.setCellData(unCheckedRow, "chassisVehclNo", rtnList[13]);
            }
        }
        if (rtnList[19] == 1) {
            ds_results2.setCellData(unCheckedRow, "pdaYn", 1);
        }

        scwin.f_checkChasisNo(unCheckedRow);

        if (ds_results2.getCellData(unCheckedRow, "cntrWrkShapeCd") == "") {
            let lv_odrNo = ds_results2.getCellData(unCheckedRow, "odrNo");
            let lv_cntrSeq = ds_results2.getCellData(unCheckedRow, "cntrSeq");
            let lv_wrkStpCd = ds_results2.getCellData(unCheckedRow, "wrkStpCd");
            let lv_cnt = 0;

            if ("0047" != ds_results2.getCellData(unCheckedRow, "wrkStpCd")) {
                for (let i = 0; i < ds_results2.getRowCount(); i++) {
                    if ("B" == ds_results2.getCellData(i, "reqClsCd") || "C" == ds_results2.getCellData(i, "reqClsCd")) {
                        if (i != unCheckedRow
                            && lv_wrkStpCd != ds_results2.getCellData(i, "wrkStpCd")
                            && "0047" != ds_results2.getCellData(i, "wrkStpCd")
                            && ds_results2.getCellData(i, "alloccarCls") == "N"
                            && ds_results2.getCellData(i, "vehclNo") == ""
                            && lv_cnt == 0) {
                            scwin._setVehclDataToRow(i, rtnList);
                            scwin.f_checkChasisNo(i);
                            lv_cnt++;
                        }
                    } else {
                        if (i != unCheckedRow
                            && lv_odrNo == ds_results2.getCellData(i, "odrNo")
                            && lv_cntrSeq == ds_results2.getCellData(i, "cntrSeq")
                            && "0047" != ds_results2.getCellData(i, "wrkStpCd")) {
                            scwin._setVehclDataToRow(i, rtnList);
                            scwin.f_checkChasisNo(i);
                        }
                    }
                }
            }
        }

        sbm_retrieveChassis.action = "/tn.op.transwrkindict.cntr.RetrieveCarInspInfoCMD.do?chassShortNo=" + ds_results2.getCellData(ds_results2.getRowPosition(), "vehclShortNo");
        await $c.sbm.execute(sbm_retrieveChassis);
    } else {
        ds_results2.undoRow(row);
        return false;
    }
};

scwin._setVehclDataToRow = async function(i, rtnList) {
    ds_results2.setCellData(i, "vehclShortNo", rtnList[0]);
    ds_results2.setCellData(i, "vehclNo", rtnList[1]);
    ds_results2.setCellData(i, "vehclClntNo", rtnList[7]);
    ds_results2.setCellData(i, "vehclClntNm", rtnList[8]);
    ds_results2.setCellData(i, "drvNm", rtnList[18]);
    ds_results2.setCellData(i, "mpNo", rtnList[17]);
    ds_results2.setCellData(i, "eqCd", rtnList[4]);
    ds_results2.setCellData(i, "posnClsCd", rtnList[21]);
    if (ds_results2.getCellData(i, "chassisEqCd") == "") {
        if (ds_results2.getCellData(i, "posnClsCd") == "W" || ds_results2.getCellData(i, "posnClsCd") == "G") {
            ds_results2.setCellData(i, "chassShortNo", "");
            ds_results2.setCellData(i, "chassisEqCd", "");
            ds_results2.setCellData(i, "chassisKndCd", "");
            ds_results2.setCellData(i, "chassisVehclNo", "");
        } else {
            ds_results2.setCellData(i, "chassShortNo", rtnList[14]);
            ds_results2.setCellData(i, "chassisEqCd", rtnList[12]);
            ds_results2.setCellData(i, "chassisKndCd", rtnList[16]);
            ds_results2.setCellData(i, "chassisVehclNo", rtnList[13]);
        }
    }
    if (rtnList[19] == 1) {
        ds_results2.setCellData(i, "pdaYn", 1);
    }
};

scwin.f_checkChasisNo = async function(row) {
    if ((ds_results2.getCellData(row, "posnClsCd") == "W" || ds_results2.getCellData(row, "posnClsCd") == "J")
        && ds_results2.getCellData(row, "alloccarCls") == "N") {
        let vOdrNo = ds_results2.getCellData(row, "odrNo");
        let vCntrSeq = ds_results2.getCellData(row, "cntrSeq");

        if (ds_results2.getCellData(row, "chassShortNo") == "1111") {
            await $c.win.alert("위수탁/자차인경우 샤시가 1111 올수가 없습니다. TR에 지정된 TL을 입력하세요");
            ds_results2.setCellData(row, "chassShortNo", "");
            ds_results2.setCellData(row, "chassisEqCd", "");
            ds_results2.setCellData(row, "chassisKndCd", "");
            ds_results2.setCellData(row, "chassisVehclNo", "");

            for (let i = 0; i < ds_results2.getRowCount(); i++) {
                if (vOdrNo == ds_results2.getCellData(i, "odrNo") && vCntrSeq == ds_results2.getCellData(i, "cntrSeq")) {
                    ds_results2.setCellData(i, "chassShortNo", "");
                    ds_results2.setCellData(i, "chassisEqCd", "");
                    ds_results2.setCellData(i, "chassisKndCd", "");
                    ds_results2.setCellData(i, "chassisVehclNo", "");
                }
            }
        }
    }
};

