scwin.f_setDptArvDh = async function() {
    let rsltsCnt = 0;
    if ((ica_rsltsDptDd.getValue() == "" && em_rsltsDptHh.getValue() == "")
        && (ica_rsltsArvDd.getValue() == "" && em_rsltsArvHh.getValue() == "")) {
        await $c.win.alert("출발실적일시, 도착실적일시를  입력해야 합니다.");
        ica_rsltsDptDd.setFocus();
        return false;
    }

    for (let i = 0; i < ds_results.getRowCount(); i++) {
        if (ds_results.getCellData(i, "chk") == 1) {
            if (ds_results.getCellData(i, "outMgntYn") == 1) {
                ds_results.setCellData(i, "rsltsDptDd", ica_rsltsDptDd.getValue());
                ds_results.setCellData(i, "rsltsDptHh", em_rsltsDptHh.getValue());
            }
            if (ds_results.getCellData(i, "inMgntYn") == 1) {
                ds_results.setCellData(i, "rsltsArvDd", ica_rsltsArvDd.getValue());
                ds_results.setCellData(i, "rsltsArvHh", em_rsltsArvHh.getValue());
            }
            ds_results.setCellData(i, "sealNo", em_sealNo.getValue());
            rsltsCnt++;
        }
    }

    if (rsltsCnt == 0) {
        await $c.win.alert("실적일시가 세팅되지 않았습니다.");
        return false;
    }
    await $c.win.alert(rsltsCnt + " 개의 행에 실적일시가 세팅되었습니다.");
};

