scwin.gr_results2_oncellclick = async function(rowIndex, columnIndex, columnId) {
    if (columnId == "combine") {
        if (ds_results2.getCellData(rowIndex, "combine") == 1) {
            if (ds_results2.getCellData(rowIndex, "cmpstcrgNo") != "") {
                await $c.win.alert("컨테이너" + ds_results2.getCellData(rowIndex, "cntrNo") + "는 이미 combine된 컨테이너입니다.");
                ds_results2.undoRow(rowIndex);
                return false;
            }
        }
    }

    let lv_odrNo = ds_results2.getCellData(rowIndex, "odrNo");
    let lv_cntrSeq = ds_results2.getCellData(rowIndex, "cntrSeq");
    let lv_chk = ds_results2.getCellData(rowIndex, "chk");
    let lv_wrkStpCd = ds_results2.getCellData(rowIndex, "wrkStpCd");
    let lv_cnt = 0;

    if (ds_results2.getCellData(rowIndex, "alloccarCls") == "Y") {
        ds_results2.setCellData(rowIndex, "chk", 0);
        ds_results2.setCellData(rowIndex, "scalYn", ds_results2.getCellData(rowIndex, "scalYn"));
    } else {
        if ("0047" != ds_results2.getCellData(rowIndex, "wrkStpCd")) {
            for (let i = 0; i < ds_results2.getRowCount(); i++) {
                if ("B" == ds_results2.getCellData(i, "reqClsCd") || "C" == ds_results2.getCellData(i, "reqClsCd")) {
                    if (i != rowIndex
                        && lv_wrkStpCd != ds_results2.getCellData(i, "wrkStpCd")
                        && "0047" != ds_results2.getCellData(i, "wrkStpCd")
                        && lv_cnt == 0) {
                        if (ds_results2.getCellData(i, "alloccarCls") == "Y") {
                            ds_results2.setCellData(i, "chk", 0);
                        } else {
                            ds_results2.setCellData(i, "chk", lv_chk);
                            lv_cnt++;
                        }
                    }
                } else {
                    if (i != rowIndex
                        && lv_odrNo == ds_results2.getCellData(i, "odrNo")
                        && lv_cntrSeq == ds_results2.getCellData(i, "cntrSeq")
                        && "0047" != ds_results2.getCellData(i, "wrkStpCd")) {
                        if (ds_results2.getCellData(i, "alloccarCls") == "Y") {
                            ds_results2.setCellData(i, "chk", 0);
                        } else {
                            ds_results2.setCellData(i, "chk", lv_chk);
                        }
                    }
                }
            }
        }
    }
};

scwin.gr_results2_ontextimageclick = async function(rowIndex, columnIndex, columnId) {
    switch (columnId) {
        case "vehclShortNo":
            scwin.f_retrieveVehclInGrid();
            break;
        case "chassShortNo":
            scwin.f_openCommPopUpGrid(2, rowIndex, 'T');
            break;
    }
};

scwin.gr_results2_oneditend = async function(rowIndex, columnIndex, columnId, oldValue, newValue) {
    switch (columnId) {
        case "vehclShortNo":
            if (ds_results2.getCellData(rowIndex, "vehclShortNo") == "") {
                ds_results2.setCellData(rowIndex, "vehclShortNo", "");
                ds_results2.setCellData(rowIndex, "vehclNo", "");
                ds_results2.setCellData(rowIndex, "vehclClntNo", "");
                ds_results2.setCellData(rowIndex, "vehclClntNm", "");
                ds_results2.setCellData(rowIndex, "drvNm", "");
                ds_results2.setCellData(rowIndex, "mpNo", "");
                ds_results2.setCellData(rowIndex, "eqCd", "");
                ds_results2.setCellData(rowIndex, "chassShortNo", "");
                ds_results2.setCellData(rowIndex, "chassisEqCd", "");
                ds_results2.setCellData(rowIndex, "chassisKndCd", "");
                ds_results2.setCellData(rowIndex, "chassisVehclNo", "");
            } else {
                scwin.f_retrieveVehclInGrid();
            }
            break;
        case "chassShortNo":
            scwin.f_openCommPopUpGrid(2, rowIndex, 'T');
            break;
    }
};

scwin.gr_results2_oncloseup = async function(rowIndex, columnIndex, columnId) {
    switch (columnId) {
        case "cntrWrkShapeCd":
            if (ds_results2.getCellData(rowIndex, "cntrWrkShapeCd") != "") {
                if (ds_results2.getCellData(rowIndex, "wrkStpCd") == "0002") {
                    for (let i = 0; i < ds_results2.getRowCount(); i++) {
                        if (ds_results2.getCellData(rowIndex, "odrNo") == ds_results2.getCellData(i, "odrNo")
                            && ds_results2.getCellData(rowIndex, "cntrSeq") == ds_results2.getCellData(i, "cntrSeq")
                            && ds_results2.getCellData(rowIndex, "vehclNo") == ds_results2.getCellData(i, "vehclNo")
                            && ds_results2.getCellData(i, "wrkStpCd") == "0003") {
                            ds_results2.setCellData(i, "vehclShortNo", "");
                            ds_results2.setCellData(i, "vehclNo", "");
                            ds_results2.setCellData(i, "vehclClntNo", "");
                            ds_results2.setCellData(i, "vehclClntNm", "");
                            ds_results2.setCellData(i, "drvNm", "");
                            ds_results2.setCellData(i, "mpNo", "");
                            ds_results2.setCellData(i, "eqCd", "");
                            ds_results2.setCellData(i, "chassShortNo", "");
                            ds_results2.setCellData(i, "chassisEqCd", "");
                            ds_results2.setCellData(i, "chassisKndCd", "");
                            ds_results2.setCellData(i, "chassisVehclNo", "");
                            break;
                        }
                    }
                } else {
                    await $c.win.alert("DOOR운송 단계만 선택할 수 있습니다.");
                    ds_results2.undoRow(rowIndex);
                    return false;
                }
            } else {
                ds_results2.setCellData(rowIndex, "vehclShortNo", "");
                ds_results2.setCellData(rowIndex, "vehclNo", "");
                ds_results2.setCellData(rowIndex, "vehclClntNo", "");
                ds_results2.setCellData(rowIndex, "vehclClntNm", "");
                ds_results2.setCellData(rowIndex, "drvNm", "");
                ds_results2.setCellData(rowIndex, "mpNo", "");
                ds_results2.setCellData(rowIndex, "eqCd", "");
                ds_results2.setCellData(rowIndex, "chassShortNo", "");
                ds_results2.setCellData(rowIndex, "chassisEqCd", "");
                ds_results2.setCellData(rowIndex, "chassisKndCd", "");
                ds_results2.setCellData(rowIndex, "chassisVehclNo", "");
            }
            break;
    }
};

scwin.gr_results2_onheaderclick = async function(columnIndex, columnId, bCheck) {
    if (columnId == "chk") {
        for (let i = 0; i < ds_results2.getRowCount(); i++) {
            if (ds_results2.getCellData(i, "alloccarCls") == "N") {
                ds_results2.setCellData(i, "chk", bCheck);
            }
            if (bCheck == 0) {
                ds_results2.undoRow(i);
            }
        }
    }
};

scwin.ds_results2_onrowpositionchange = async function(rowIndex) {
    let curPos = ds_results2.getRowPosition();
    if (scwin.g_chkScroll2) {
        dma_retrieveCntrPerWrkPrst.set("odrNo", ds_results2.getCellData(ds_results2.getRowPosition(), "odrNo"));
        if ("A" == ds_results2.getCellData(ds_results2.getRowPosition(), "reqClsCd")
            || "D" == ds_results2.getCellData(ds_results2.getRowPosition(), "reqClsCd")) {
            dma_retrieveCntrPerWrkPrst.set("cntrSeq", ds_results2.getCellData(ds_results2.getRowPosition(), "cntrSeq"));
        }
        await $c.sbm.execute(sbm_retrieveCntrPerWrkPrst);

        ds_dcScList.filter();
    }
};

